+        rowid_alias_name: Option<&str>,
+        rowid_alias_column_index: Option<usize>,
+    ) -> Option<Arc<[PreparedMemValueSource]>> {
+        let mut sources = Vec::new();
+        for column in columns {
+            match column {
+                ResultColumn::Star => {
+                    sources.extend((0..table.columns.len()).map(|column_index| {
+                        if Some(column_index) == rowid_alias_column_index {
+                            PreparedMemValueSource::Rowid
+                        } else {
+                            PreparedMemValueSource::Column(column_index)
+                        }
+                    }));
+                }
+                ResultColumn::TableStar(name)
+                    if name.schema.is_none()
+                        && (name.name.eq_ignore_ascii_case(table_label)
+                            || name.name.eq_ignore_ascii_case(&table.name)) =>
+                {
+                    sources.extend((0..table.columns.len()).map(|column_index| {
+                        if Some(column_index) == rowid_alias_column_index {
+                            PreparedMemValueSource::Rowid
+                        } else {
+                            PreparedMemValueSource::Column(column_index)
+                        }
+                    }));
+                }
+                ResultColumn::Expr { expr, .. } => {
+                    sources.push(select_table_value_source(
+                        table,
+                        table_label,
+                        expr,
+                        rowid_alias_name,
+                    )?);
+                }
+                ResultColumn::TableStar(_) => return None,
+            }
+        }
+        (!sources.is_empty()).then_some(Arc::from(sources))
+    }
